  // FOSSILS (8)
  fossils: [
    { name: 'Lyme Regis, Jurassic Coast', lat: 50.73, lng: -2.93, desc: 'The fossil capital of England, where Mary Anning discovered the first ichthyosaur. Walk the beach at low tide and you\'ll find ammonites, belemnites, and crinoids in the shale.', top: true },
    { name: 'Charmouth Beach', lat: 50.74, lng: -2.9, desc: 'Prime fossil-hunting beach next to Lyme Regis, where cliff falls regularly expose new finds. The Heritage Coast Centre runs guided walks — bring a small hammer and safety glasses.', top: true },
    { name: 'Kimmeridge Bay', lat: 50.61, lng: -2.13, desc: 'Wave-cut rock platforms packed with 150-million-year-old Jurassic fossils. Ammonites and bivalves are visible in the ledges at low tide — some as big as dinner plates.', top: true },
    { name: 'Whitby Jet Coast', lat: 54.49, lng: -0.61, desc: 'The Yorkshire coast around Whitby is famous for jet, a fossilised wood prized since the Bronze Age. Victorian Whitby jet jewellery is still made and sold in the town\'s workshops.', top: true },
    { name: 'Fossil Forest, Dorset', lat: 50.62, lng: -2.05, desc: 'Petrified tree stumps from 150 million years ago, preserved in clifftop limestone east of Lulworth Cove. You can see the actual trunks and algal growths that encrusted them.', top: true },
    { name: 'Mary Anning Museum', lat: 50.73, lng: -2.94, desc: 'Lyme Regis museum celebrating the greatest fossil hunter who ever lived. Mary Anning\'s discoveries revolutionised our understanding of prehistoric life — she deserves the fame.', top: true },
    { name: 'Dinosaurland, Lyme Regis', lat: 50.73, lng: -2.94, desc: 'Quirky independent fossil museum crammed with ichthyosaurs, ammonites, and local finds. Run by passionate collectors — a brilliant introduction before heading to the beach to hunt your own.', top: true },
    { name: 'Hunstanton Cliffs', lat: 52.94, lng: 0.49, desc: 'Unique striped cliffs of red chalk, white chalk, and brown carstone on the Norfolk coast. One of the few places in England where the cliffs face west — sunset turns them gold.', top: true }
  ],

  // FERRIES (5)
  ferries: [
    { name: 'Isle of Wight Ferry (Lymington–Yarmouth)', lat: 50.76, lng: -1.53, desc: 'Wightlink car ferry across the Solent from Lymington to Yarmouth. Book a bike space — the Island\'s Military Road and Needles are well worth the crossing.', top: true },
    { name: 'Red Funnel (Southampton–Cowes)', lat: 50.9, lng: -1.3, desc: 'Vehicle ferry from Southampton to East Cowes on the Isle of Wight. The longer crossing but drops you closer to the eastern Island roads and Sandown.', top: true },
    { name: 'Windermere Ferry', lat: 54.35, lng: -2.95, desc: 'Cable ferry crossing Windermere between Bowness and Far Sawrey. A scenic shortcut that saves riding around the lake — bikes go on cheaply and the views are lovely.', top: true },
    { name: 'Dartmouth–Kingswear Ferry', lat: 50.35, lng: -3.58, desc: 'Lower vehicle ferry crossing the River Dart estuary. Bikes ride on for a small fee — the crossing takes just a few minutes with views of the naval college and estuary.', top: true },
    { name: 'Torpoint Ferry, Plymouth', lat: 50.37, lng: -4.19, desc: 'Chain ferry crossing the Tamar between Plymouth and Torpoint. Three ferries run continuously — free for bikes. The gateway between Devon and the Rame Peninsula in Cornwall.', top: true }
  ],

